import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class ThemeQueryPlanRunBenchmarkTest {

	@TempDir
	Path tempDir;

	@Test
	void trialTeardownPrintsTelemetryPlan() throws Exception {
		ThemeQueryPlanRunBenchmark.ExecutionState state = new ThemeQueryPlanRunBenchmark.ExecutionState();
		state.themeName = Theme.MEDICAL_RECORDS.name();
		state.z_queryIndex = 0;
		state.sketchEstimatorEnabled = false;
		state.sketchEstimatorStrategy = "fastagms";
		state.query = "SELECT * WHERE { ?s ?p ?o }";
		setTheme(state, Theme.MEDICAL_RECORDS);

		SailRepository repository = new SailRepository(
				new LmdbStore(new File(tempDir.toFile(), "store"), ConfigUtil.createConfig()));
		PrintStream previousOut = System.out;
		ByteArrayOutputStream out = new ByteArrayOutputStream();

		try {
			state.connection = repository.getConnection();
			System.setOut(new PrintStream(out, true, StandardCharsets.UTF_8));

			state.tearDown();

			String output = out.toString(StandardCharsets.UTF_8);
			int telemetryIndex = output.indexOf("### Telemetry Query - Trial teardown ###");
			int renderedIndex = output.indexOf("### Rendered Optimized SPARQL - Trial teardown ###");
			assertTrue(telemetryIndex >= 0, output);
			assertTrue(renderedIndex > telemetryIndex, output);
			assertTrue(output.substring(renderedIndex).contains("SELECT"), output);
		} finally {
			System.setOut(previousOut);
			if (state.connection != null) {
				state.connection.close();
			}
			repository.shutDown();
		}
	}

	@Test
	void medicalQ7ValuesVariantForcesFiniteCodeAnchorQuery() throws Exception {
		Method method = ThemeQueryPlanRunBenchmark.BaseState.class.getDeclaredMethod("queryForVariant", Theme.class,
				int.class, String.class);
		method.setAccessible(true);

		String query = (String) method.invoke(null, Theme.MEDICAL_RECORDS, 7, "medical-q7-values");

		assertTrue(query.contains("VALUES ?code { \"MED-1000\" \"MED-1001\" }"), query);
		assertFalse(query.contains("FILTER(?code = \"MED-1000\" || ?code = \"MED-1001\")"), query);
		assertTrue(query.contains("MINUS"), query);
	}

	@Test
	void medicalQ7PlacementVariantsRenderRequestedInputOrder() throws Exception {
		Method method = ThemeQueryPlanRunBenchmark.BaseState.class.getDeclaredMethod("queryForVariant", Theme.class,
				int.class, String.class);
		method.setAccessible(true);

		String valuesTop = (String) method.invoke(null, Theme.MEDICAL_RECORDS, 7, "values-top-type-code");
		String typeFirst = (String) method.invoke(null, Theme.MEDICAL_RECORDS, 7, "type-values-code");
		String codeFirst = (String) method.invoke(null, Theme.MEDICAL_RECORDS, 7, "values-code-type");

		assertOrder(valuesTop, "VALUES ?code", "?med a med:Medication", "?med med:code ?code");
		assertOrder(typeFirst, "?med a med:Medication", "VALUES ?code", "?med med:code ?code");
		assertOrder(codeFirst, "VALUES ?code", "?med med:code ?code", "?med a med:Medication");
	}

	private static void setTheme(ThemeQueryPlanRunBenchmark.BaseState state, Theme theme)
			throws ReflectiveOperationException {
		Field field = ThemeQueryPlanRunBenchmark.BaseState.class.getDeclaredField("theme");
		field.setAccessible(true);
		field.set(state, theme);
	}

	private static void assertOrder(String query, String first, String second, String third) {
		int firstIndex = query.indexOf(first);
		int secondIndex = query.indexOf(second);
		int thirdIndex = query.indexOf(third);
		assertTrue(firstIndex >= 0, query);
		assertTrue(secondIndex > firstIndex, query);
		assertTrue(thirdIndex > secondIndex, query);
	}
}
